def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        remainder = capacity - item
        if ratio > 3:
            priorities[i] = 3000 + (ratio - 3)**2 * 300
        elif 2 < ratio <= 3:
            priorities[i] = 1000 + (ratio - 2) * 250
            if remainder < 0.05 * capacity:
                priorities[i] += 50
        elif 1 < ratio <= 2:
            priorities[i] = 600 + (ratio - 1) * 150
            if remainder < 0.1 * capacity:
                priorities[i] -= 30
        elif ratio == 1:
            priorities[i] = 200 if i % 3 == 0 else 180
        else:
            score = 0
            for j in range(1, 12):
                temp = ((capacity - item) ** j) / (capacity ** j)
                if temp < 0.03:
                    score += temp * 120 / j
                elif 0.03 <= temp < 0.15:
                    score += temp * 30 / (j**1.5)
                elif 0.15 <= temp < 0.5:
                    score += temp * 12 / (j**2)
                else:
                    score += temp * 2 / (j**3)
            adjustment = 0
            for k in range(1,5):
                adjustment += ((item / (capacity + k * 0.5)) ** k) * 15 / (k + 2)
            priorities[i] = (1 / (score + 1.5)) + adjustment
            if remainder < 0.2 * capacity and remainder > 0.05 * capacity:
                priorities[i] -= 0.5 * remainder / capacity
            elif remainder <= 0.05 * capacity:
                priorities[i] -= 0.2 * remainder / capacity
        if i % 4 == 0:
            priorities[i] += np.sin(i + item) / (capacity + 1)
        elif i % 4 == 1:
            priorities[i] -= np.cos(i + item) / (capacity + 2)
        elif i % 4 == 2:
            priorities[i] += np.log1p(capacity + i) * 0.1
        else:
            priorities[i] -= np.sqrt(capacity + item) * 0.05
        if item > capacity * 0.85 and item < capacity:
            priorities[i] *= 0.85
        if remainder < 0:
            priorities[i] = float('inf')
    for boost_round in range(2):
        for i in range(len(priorities)):
            if priorities[i] < 50:
                priorities[i] *= 1.1 + 0.05 * boost_round
            else:
                priorities[i] -= 0.02 * i
    return priorities
